def greet(name: str) -> str:
    return "Hello, " + name

print(greet("Alice"))

def total(scores: list[int]) -> int:
    return sum(scores)

print(total([10, 20, 30]))

def find_user(user_id: int) -> str | None:
    users = {1: "Alice", 2: "Bob"}
    return users.get(user_id)

print(find_user(1))
print(find_user(99))
